import React, { useEffect, useMemo, useState } from "react";
import { useNavigate, useParams } from "react-router-dom";
import LoginForm from "./LoginForm";
import RegisterForm from "./RegisterForm";

export default function AuthPage() {
  const navigate = useNavigate();
  const { mode } = useParams();
  const [error, setError] = useState("");
  const safeMode = useMemo(() => (mode === "register" ? "register" : "login"), [mode]);

  useEffect(() => {
    if (mode !== "login" && mode !== "register") {
      navigate("/auth/login", { replace: true });
    }
  }, [mode, navigate]);

  return (
    <div className="auth-shell">
      <div className="auth-waves" aria-hidden="true">
        <svg className="auth-wave wave-1" viewBox="0 0 1440 320" preserveAspectRatio="none">
          <path d="M0,192 C240,256 480,96 720,144 C960,192 1200,288 1440,224 L1440 320 L0 320 Z"></path>
        </svg>
        <svg className="auth-wave wave-2" viewBox="0 0 1440 320" preserveAspectRatio="none">
          <path d="M0,224 C200,176 480,272 720,224 C960,176 1200,96 1440,160 L1440 320 L0 320 Z"></path>
        </svg>
        <svg className="auth-wave wave-3" viewBox="0 0 1440 320" preserveAspectRatio="none">
          <path d="M0,256 C240,208 480,336 720,272 C960,208 1200,176 1440,208 L1440 320 L0 320 Z"></path>
        </svg>
      </div>
      <div className="auth-card glass">
        <div className="brand-block">
          <img src="/wavvy-wordmark.png" alt="Wavvy" className="brand-wordmark" />
          <p>Realtime conversations that actually flow.</p>
        </div>
        {safeMode === "login" ? <LoginForm setError={setError} /> : <RegisterForm setError={setError} />}
        {error ? <p className="error-text">{error}</p> : null}
      </div>
    </div>
  );
}
